func assetLocationValue(asset *AssetDetail) string {
	if asset == nil || asset.LocationID == nil {
		return "0"
	}
	return fmt.Sprintf("%d", *asset.LocationID)
}

func assetFormValue(asset *AssetDetail, field string) string {
	if asset == nil {
		return ""
	}
	switch field {
	case "Name":
		return asset.Name
	case "SerialNumber":
		return asset.SerialNumber
	case "Model":
		return asset.Model
	case "Manufacturer":
		return asset.Manufacturer
	case "Notes":
		return asset.Notes
	}
	return ""
}

func assetTypeSelected(asset *AssetDetail, value int64) bool {
	if asset == nil {
		return false
	}
	return asset.AssetTypeID == value
}

func assetStatusSelected(asset *AssetDetail, value int64) bool {
	if asset == nil || asset.AssetStatusID == nil {
		return false
	}
	return *asset.AssetStatusID == value
}

func assetCustomerSelected(asset *AssetDetail, value int64) bool {
	if asset == nil {
		return false
	}
	return asset.CustomerID == value
}

func assetLocationSelected(asset *AssetDetail, value int64) bool {
	if asset == nil || asset.LocationID == nil {
		return false
	}
	return *asset.LocationID == value
}

func assetDateValue(asset *AssetDetail, field string) string {
	if asset == nil {
		return ""
	}
	var t *time.Time
	if field == "InstalledAt" {
		t = asset.InstalledAt
	} else if field == "WarrantyExpires" {
		t = asset.WarrantyExpires
	}
	if t == nil {
		return ""
	}
	return t.Format("2006-01-02")
}

func assetFormTitle(isNew bool) string {
	if isNew {
		return "New Asset"
	}
	return "Edit Asset"
}

func assetFormButtonText(isNew bool) string {
	if isNew {
		return "Create"
	}
	return "Update"
}

func assetFormAction(isNew bool, asset *AssetDetail) string {
	if isNew {
		return "/assets"
	}
	if asset != nil {
		return fmt.Sprintf("/assets/%d", asset.ID)
	}
	return "/assets"
}

